import { FormEvent, MouseEvent, useEffect, useMemo, useRef, useState } from "react";
import { Link, useLocation, useSearch } from "wouter";
import { ArrowRight, Calculator, Clock3, Search, Sparkles, X } from "lucide-react";
import { Helmet } from "react-helmet-async";
import SEOHead from "@/components/SEOHead";
import { getMeta } from "@/data/calcMeta";
import { calculatorRoutes, SITE_URL } from "@/data/siteRoutes";

const CATEGORY_COLOR: Record<string, string> = {
  Financial: "text-sky-600 bg-sky-50 dark:text-sky-400 dark:bg-sky-950/50",
  Health: "text-teal-600 bg-teal-50 dark:text-teal-400 dark:bg-teal-950/50",
  Math: "text-violet-600 bg-violet-50 dark:text-violet-400 dark:bg-violet-950/50",
  Freelance: "text-indigo-600 bg-indigo-50 dark:text-indigo-400 dark:bg-indigo-950/50",
  Dropshipping: "text-emerald-600 bg-emerald-50 dark:text-emerald-400 dark:bg-emerald-950/50",
  YouTube: "text-red-600 bg-red-50 dark:text-red-400 dark:bg-red-950/50",
  Social: "text-pink-600 bg-pink-50 dark:text-pink-400 dark:bg-pink-950/50",
  Income: "text-violet-600 bg-violet-50 dark:text-violet-400 dark:bg-violet-950/50",
};

const RECENT_SEARCHES_KEY = "calchive-recent-searches";
const MAX_RECENT_SEARCHES = 6;

const calculators = calculatorRoutes.map((route) => {
  const meta = getMeta(route.path);
  const title = meta?.h1?.replace(/\s[--]\s.*$/, "") ?? route.path.replace(/^\//, "").replace(/-/g, " ");
  const description = meta?.description ?? `Use this free online ${route.category.toLowerCase()} calculator for instant results.`;
  return {
    href: route.path,
    title,
    description,
    category: route.category,
    keywords: `${title} ${description} ${meta?.keywords ?? ""} ${route.category}`.toLowerCase(),
  };
});

const categories = ["All", ...Array.from(new Set(calculators.map((tool) => tool.category))).sort()];
const suggestionTerms = Array.from(
  new Set(
    calculators.flatMap((tool) => [
      tool.title,
      tool.category,
      ...tool.title.toLowerCase().split(/[^a-z0-9]+/).filter((term) => term.length > 2),
    ]),
  ),
);

function getInitialQuery(searchString: string) {
  return new URLSearchParams(searchString).get("q")?.trim() ?? "";
}

function loadRecentSearches() {
  if (typeof window === "undefined") return [];
  try {
    const parsed = JSON.parse(localStorage.getItem(RECENT_SEARCHES_KEY) || "[]");
    return Array.isArray(parsed) ? parsed.filter((item): item is string => typeof item === "string").slice(0, MAX_RECENT_SEARCHES) : [];
  } catch {
    return [];
  }
}

function getDistance(a: string, b: string) {
  const first = a.toLowerCase();
  const second = b.toLowerCase();
  const matrix = Array.from({ length: first.length + 1 }, (_, i) => [i]);
  for (let j = 1; j <= second.length; j += 1) matrix[0][j] = j;
  for (let i = 1; i <= first.length; i += 1) {
    for (let j = 1; j <= second.length; j += 1) {
      const cost = first[i - 1] === second[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(matrix[i - 1][j] + 1, matrix[i][j - 1] + 1, matrix[i - 1][j - 1] + cost);
    }
  }
  return matrix[first.length][second.length];
}

export default function SearchPage() {
  const searchString = useSearch();
  const [, setLocation] = useLocation();
  const initialQuery = getInitialQuery(searchString);
  const [query, setQuery] = useState(initialQuery);
  const [category, setCategory] = useState("All");
  const [recentSearches, setRecentSearches] = useState<string[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const formRef = useRef<HTMLFormElement>(null);
  const normalizedQuery = query.trim().toLowerCase();

  useEffect(() => {
    setRecentSearches(loadRecentSearches());
  }, []);

  useEffect(() => {
    setQuery(initialQuery);
  }, [initialQuery]);

  useEffect(() => {
    const onPointerDown = (event: PointerEvent) => {
      if (!formRef.current?.contains(event.target as Node)) setIsFocused(false);
    };
    document.addEventListener("pointerdown", onPointerDown);
    return () => document.removeEventListener("pointerdown", onPointerDown);
  }, []);

  const saveRecentSearch = (term: string) => {
    const clean = term.trim();
    if (!clean) return;
    const next = [clean, ...recentSearches.filter((item) => item.toLowerCase() !== clean.toLowerCase())].slice(0, MAX_RECENT_SEARCHES);
    setRecentSearches(next);
    localStorage.setItem(RECENT_SEARCHES_KEY, JSON.stringify(next));
  };

  const results = useMemo(() => {
    return calculators
      .filter((tool) => category === "All" || tool.category === category)
      .filter((tool) => {
        if (!normalizedQuery) return true;
        return tool.keywords.includes(normalizedQuery);
      });
  }, [category, normalizedQuery]);

  const suggestions = useMemo(() => {
    if (!normalizedQuery) return [];
    return calculators
      .filter((tool) => category === "All" || tool.category === category)
      .filter((tool) => tool.keywords.includes(normalizedQuery))
      .slice(0, 8);
  }, [category, normalizedQuery]);

  const didYouMean = useMemo(() => {
    if (!normalizedQuery || results.length > 0) return "";
    const best = suggestionTerms
      .map((term) => ({ term, distance: getDistance(normalizedQuery, term.toLowerCase()) }))
      .sort((a, b) => a.distance - b.distance)[0];
    if (!best || best.distance > Math.max(2, Math.floor(normalizedQuery.length * 0.45))) return "";
    return best.term;
  }, [normalizedQuery, results.length]);

  const showAutocomplete = (normalizedQuery && suggestions.length > 0) || (isFocused && !normalizedQuery && recentSearches.length > 0);

  const title = initialQuery
    ? `Search Results for ${initialQuery} Calculators`
    : "Search Free Online Calculators";

  const description = initialQuery
    ? `Search CalcHive for ${initialQuery} calculators. Find free online calculators with instant results, no signup required, and mobile-friendly tools.`
    : "Search CalcHive's full library of free online calculators for finance, health, math, business, date, time, measurement, and everyday tools.";

  const itemListSchema = {
    "@context": "https://schema.org",
    "@type": "ItemList",
    "name": title,
    "description": description,
    "numberOfItems": results.length,
    "itemListElement": results.slice(0, 50).map((tool, index) => ({
      "@type": "ListItem",
      "position": index + 1,
      "name": tool.title,
      "description": tool.description,
      "url": `${SITE_URL}${tool.href}`,
    })),
  };

  const onSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const next = query.trim();
    saveRecentSearch(next);
    setIsFocused(false);
    setLocation(next ? `/search?q=${encodeURIComponent(next)}` : "/search");
  };

  const runSearch = (term: string) => {
    setQuery(term);
    saveRecentSearch(term);
    setIsFocused(false);
    setLocation(`/search?q=${encodeURIComponent(term)}`);
  };

  const clearRecentSearches = (event: MouseEvent<HTMLButtonElement>) => {
    event.preventDefault();
    event.stopPropagation();
    setRecentSearches([]);
    localStorage.removeItem(RECENT_SEARCHES_KEY);
  };

  return (
    <>
      <SEOHead
        title={title}
        description={description}
        canonical="/search"
        keywords="search free online calculators, calculator search, free calculator finder, online calculator tools"
        category="company"
        breadcrumbName="Search"
      />
      <Helmet>
        <script type="application/ld+json">{JSON.stringify(itemListSchema)}</script>
      </Helmet>
      <main className="min-h-screen bg-background">
        <section className="mx-auto w-full max-w-6xl px-4 py-8 sm:px-6 lg:px-8">
          <div className="mx-auto mb-7 max-w-3xl text-center">
            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-2xl bg-primary/10 text-primary">
              <Search className="h-6 w-6" />
            </div>
            <h1 className="text-3xl font-black tracking-tight text-foreground sm:text-4xl">
              {title}
            </h1>
            <p className="mt-3 text-base leading-relaxed text-muted-foreground">
              Search all CalcHive calculators by name, category, keyword, or use case.
            </p>
          </div>

          <form ref={formRef} onSubmit={onSubmit} className="relative mx-auto mb-4 flex max-w-3xl gap-2">
            <div className="relative flex-1">
              <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <input
                type="search"
                value={query}
                onChange={(event) => setQuery(event.target.value)}
                onInput={(event) => setQuery(event.currentTarget.value)}
                onFocus={() => setIsFocused(true)}
                placeholder="Search calculators..."
                className="w-full rounded-xl border border-border bg-card py-3 pl-10 pr-4 text-sm text-foreground shadow-xs outline-none transition-all placeholder:text-muted-foreground focus:border-primary focus:ring-2 focus:ring-primary/30"
                autoFocus
              />
              {showAutocomplete && (
                <div data-search-autocomplete className="absolute left-0 right-0 top-full z-50 mt-2 max-h-96 overflow-y-auto rounded-2xl border border-border bg-card p-2 shadow-xl">
                  {normalizedQuery ? (
                    <>
                      <div className="px-3 py-2 text-[11px] font-bold uppercase tracking-wide text-muted-foreground">
                        Suggestions
                      </div>
                      {suggestions.map((tool) => (
                        <Link
                          key={tool.href}
                          href={tool.href}
                          onClick={() => saveRecentSearch(tool.title)}
                          className="flex items-center gap-3 rounded-xl px-3 py-3 text-left transition-colors hover:bg-accent"
                        >
                          <span className={`flex h-9 w-9 flex-shrink-0 items-center justify-center rounded-xl ${CATEGORY_COLOR[tool.category] ?? "text-primary bg-primary/10"}`}>
                            <Calculator className="h-4 w-4" />
                          </span>
                          <span className="min-w-0 flex-1">
                            <span className="block truncate text-sm font-bold text-foreground">{tool.title}</span>
                            <span className="block truncate text-xs text-muted-foreground">{tool.category}</span>
                          </span>
                          <ArrowRight className="h-4 w-4 text-muted-foreground" />
                        </Link>
                      ))}
                    </>
                  ) : (
                    <>
                      <div className="flex items-center justify-between px-3 py-2">
                        <span className="text-[11px] font-bold uppercase tracking-wide text-muted-foreground">Recent searches</span>
                        <button type="button" onClick={clearRecentSearches} className="text-xs font-semibold text-primary hover:underline">
                          Clear
                        </button>
                      </div>
                      {recentSearches.map((term) => (
                        <button
                          key={term}
                          type="button"
                          onClick={() => runSearch(term)}
                          className="flex w-full items-center gap-3 rounded-xl px-3 py-3 text-left transition-colors hover:bg-accent"
                        >
                          <Clock3 className="h-4 w-4 text-muted-foreground" />
                          <span className="text-sm font-semibold text-foreground">{term}</span>
                        </button>
                      ))}
                    </>
                  )}
                </div>
              )}
            </div>
            <button
              type="submit"
              className="rounded-xl bg-primary px-4 py-3 text-sm font-bold text-primary-foreground shadow-sm transition-colors hover:bg-primary/90"
            >
              Search
            </button>
          </form>

          <div className="mx-auto mb-6 flex max-w-3xl gap-2 overflow-x-auto pb-1">
            {categories.map((item) => (
              <button
                key={item}
                type="button"
                onClick={() => setCategory(item)}
                className={`whitespace-nowrap rounded-full border px-3 py-1.5 text-xs font-bold transition-colors ${
                  category === item
                    ? "border-primary bg-primary text-primary-foreground"
                    : "border-border bg-card text-muted-foreground hover:border-primary/40 hover:text-foreground"
                }`}
              >
                {item}
              </button>
            ))}
          </div>

          <div className="mb-4 flex items-center justify-between gap-3">
            <p className="text-sm font-semibold text-foreground">
              {results.length} {results.length === 1 ? "result" : "results"}
              {category !== "All" ? ` in ${category}` : ""}
            </p>
            {initialQuery && (
              <Link href="/search" className="text-sm font-semibold text-primary hover:underline">
                Clear search
              </Link>
            )}
          </div>

          {results.length === 0 ? (
            <div className="rounded-2xl border border-border bg-card p-8 text-center">
              <div className="mx-auto mb-3 flex h-10 w-10 items-center justify-center rounded-xl bg-primary/10 text-primary">
                {didYouMean ? <Sparkles className="h-5 w-5" /> : <X className="h-5 w-5" />}
              </div>
              <p className="text-base font-bold text-foreground">No calculators found</p>
              <p className="mt-2 text-sm text-muted-foreground">Try a simpler keyword like loan, BMI, percentage, tax, or mortgage.</p>
              {didYouMean && (
                <button
                  type="button"
                  onClick={() => runSearch(didYouMean)}
                  className="mt-4 rounded-full border border-primary/30 bg-primary/10 px-4 py-2 text-sm font-bold text-primary transition-colors hover:bg-primary/15"
                >
                  Did you mean {didYouMean}?
                </button>
              )}
            </div>
          ) : (
            <div className="grid grid-cols-2 gap-2.5 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
              {results.map((tool) => {
                const color = CATEGORY_COLOR[tool.category] ?? "text-primary bg-primary/10";
                return (
                  <Link
                    key={tool.href}
                    href={tool.href}
                    className="group relative flex min-w-0 flex-col rounded-xl border border-border bg-card p-3 transition-all duration-150 hover:border-primary/40 hover:shadow-md active:scale-[0.98]"
                  >
                    <div className="mb-2 flex items-center gap-2">
                      <div className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-lg ${color}`}>
                        <Calculator className="h-4 w-4" />
                      </div>
                      <span className="truncate text-[9px] font-bold uppercase tracking-wide text-muted-foreground">
                        {tool.category}
                      </span>
                    </div>
                    <h2 className="mb-1 line-clamp-2 text-xs font-bold leading-snug text-foreground transition-colors group-hover:text-primary">
                      {tool.title}
                    </h2>
                    <p className="line-clamp-3 text-[10px] leading-relaxed text-muted-foreground">
                      {tool.description}
                    </p>
                    <div className="mt-auto flex justify-end pt-3">
                      <ArrowRight className="h-3.5 w-3.5 text-muted-foreground transition-all group-hover:translate-x-0.5 group-hover:text-primary" />
                    </div>
                  </Link>
                );
              })}
            </div>
          )}
        </section>
      </main>
    </>
  );
}


